import type { StaticVerse } from "../verses";

export const CH18: StaticVerse[] = [
  { chapterId: 18, id: 1, chapterName: "Liberation through Renunciation", skt: "अर्जुन उवाच।\nसंन्यासस्य महाबाहो तत्त्वमिच्छामि वेदितुम्।\nत्यागस्य च हृषीकेश पृथक्केशिनिषूदन॥", iast: "arjuna uvāca\nsaṃnyāsasya mahābāho tattvam icchāmi veditum\ntyāgasya ca hṛṣīkeśa pṛthak keśiniṣūdana", hindi: "अर्जुन बोले — हे महाबाहो, हे हृषीकेश, हे केशिनिषूदन! संन्यास और त्याग का तत्त्व अलग-अलग जानना चाहता हूँ।", english: "Arjuna said: O mighty-armed one, I wish to understand the purpose of renunciation and of the renounced order of life, O killer of the Keshi demon, master of the senses.", themes: ["Question", "Renunciation", "Sannyasa", "Tyaga"] },
  { chapterId: 18, id: 2, chapterName: "Liberation through Renunciation", skt: "श्रीभगवानुवाच।\nकाम्यानां कर्मणां न्यासं संन्यासं कवयो विदुः।\nसर्वकर्मफलत्यागं प्राहुस्त्यागं विचक्षणाः॥", iast: "śrī bhagavān uvāca\nkāmyānāṃ karmaṇāṃ nyāsaṃ saṃnyāsaṃ kavayo viduḥ\nsarvakarmaphalatyāgaṃ prāhus tyāgaṃ vicakṣaṇāḥ", hindi: "श्री भगवान् बोले — काम्यकर्मों के त्याग को विद्वान् लोग संन्यास कहते हैं और विचक्षण लोग सभी कर्मफलों के त्याग को त्याग कहते हैं।", english: "The Supreme Personality of Godhead said: The giving up of activities that are based on material desire is what great learned men call the renounced order of life. And giving up the results of all activities is what the wise call renunciation.", themes: ["Definition", "Sannyasa", "Tyaga", "Renunciation"] },
  { chapterId: 18, id: 3, chapterName: "Liberation through Renunciation", skt: "त्याज्यं दोषवदित्येके कर्म प्राहुर्मनीषिणः।\nयज्ञदानतपःकर्म न त्याज्यमिति चापरे॥", iast: "tyājyaṃ doṣavad ity eke karma prāhur manīṣiṇaḥ\nyajñadānatapaḥkarma na tyājyam iti cāpare", hindi: "कुछ मनीषी कहते हैं — 'कर्म दोषयुक्त है इसलिए त्याज्य है।' और दूसरे कहते हैं — 'यज्ञ, दान और तपस्या का कर्म त्याज्य नहीं है।'", english: "Some learned men declare that all kinds of fruitive activities should be given up as faulty, yet other sages maintain that acts of sacrifice, charity, and penance should never be abandoned.", themes: ["Debate on Renunciation", "Sacrifice", "Charity", "Austerity"] },
  { chapterId: 18, id: 4, chapterName: "Liberation through Renunciation", skt: "निश्चयं शृणु मे तत्र त्यागे भरतसत्तम।\nत्यागो हि पुरुषव्याघ्र त्रिविधः सम्प्रकीर्तितः॥", iast: "niścayaṃ śṛṇu me tatra tyāge bharatasattama\ntyāgo hi puruṣavyāghra trividhaḥ samprakīrtitaḥ", hindi: "हे भरतसत्तम, हे पुरुषव्याघ्र! त्याग में मेरा निश्चित मत सुनो। त्याग तीन प्रकार का कहा गया है।", english: "O best of the Bharatas, now hear My judgment about renunciation. O tiger among men, renunciation is declared in the scriptures to be of three kinds.", themes: ["Three Kinds of Renunciation", "Definition", "Teaching"] },
  { chapterId: 18, id: 5, chapterName: "Liberation through Renunciation", skt: "यज्ञदानतपःकर्म न त्याज्यं कार्यमेव तत्।\nयज्ञो दानं तपश्चैव पावनानि मनीषिणाम्॥", iast: "yajñadānatapaḥkarma na tyājyaṃ kāryam eva tat\nyajño dānaṃ tapaś caiva pāvanāni manīṣiṇām", hindi: "यज्ञ, दान और तपस्या का कर्म त्याज्य नहीं है — वह तो करने योग्य ही है। यज्ञ, दान और तप मनीषियों को पवित्र करते हैं।", english: "Acts of sacrifice, charity, and penance are not to be given up; they must be performed. Indeed, sacrifice, charity, and penance purify even the great souls.", themes: ["Yajna-Dana-Tapas", "Must Be Performed", "Purification", "Not to Abandon"] },
  { chapterId: 18, id: 6, chapterName: "Liberation through Renunciation", skt: "एतान्यपि तु कर्माणि सङ्गं त्यक्त्वा फलानि च।\nकर्तव्यानीति मे पार्थ निश्चितं मतमुत्तमम्॥", iast: "etāny api tu karmāṇi saṃgaṃ tyaktvā phalāni ca\nkartavyānīti me pārtha niścitaṃ matam uttamam", hindi: "हे पार्थ! ये कर्म भी आसक्ति और फलों को त्यागकर करने चाहिए — यह मेरा निश्चित और उत्तम मत है।", english: "All these activities should be performed without attachment or any expectation of result. They should be performed as a matter of duty, O son of Pritha. That is My final opinion.", themes: ["Non-attachment", "Duty", "God's Opinion", "Action"] },
  { chapterId: 18, id: 7, chapterName: "Liberation through Renunciation", skt: "नियतस्य तु संन्यासः कर्मणो नोपपद्यते।\nमोहात्तस्य परित्यागस्तामसः परिकीर्तितः॥", iast: "niyatasya tu saṃnyāsaḥ karmaṇo nopapadyate\nmohāt tasya parityāgas tāmasaḥ parikīrtitaḥ", hindi: "नियत कर्म का संन्यास उचित नहीं है। मोह से उसका त्याग तामस कहा जाता है।", english: "Prescribed duties should never be renounced. If one gives up his prescribed duties because of illusion, such renunciation is said to be in the mode of ignorance.", themes: ["Wrong Renunciation", "Tamasic", "Delusion", "Prescribed Duties"] },
  { chapterId: 18, id: 8, chapterName: "Liberation through Renunciation", skt: "दुःखमित्येव यत्कर्म कायक्लेशभयात्त्यजेत्।\nस कृत्वा राजसं त्यागं नैव त्यागफलं लभेत्॥", iast: "duḥkham ity eva yat karma kāyakleśabhayāt tyajet\nsa kṛtvā rājasaṃ tyāgaṃ naiva tyāgaphalaṃ labhet", hindi: "जो कर्म को 'यह दुखद है' मानकर शारीरिक कष्ट के भय से त्यागे — वह राजस त्याग करके त्याग का फल नहीं पाता।", english: "Anyone who gives up prescribed duties as troublesome or out of fear of bodily discomfort is said to have renounced in the mode of passion. Such action never leads to the elevation of renunciation.", themes: ["Rajasic Renunciation", "Fear", "Discomfort", "No Result"] },
  { chapterId: 18, id: 9, chapterName: "Liberation through Renunciation", skt: "कार्यमित्येव यत्कर्म नियतं क्रियतेऽर्जुन।\nसङ्गं त्यक्त्वा फलं चैव स त्यागः सात्त्विको मतः॥", iast: "kāryam ity eva yat karma niyataṃ kriyate'rjuna\nsaṃgaṃ tyaktvā phalaṃ caiva sa tyāgaḥ sāttiviko mataḥ", hindi: "हे अर्जुन! जो नियत कर्म 'करना चाहिए' मानकर आसक्ति और फल त्यागकर किया जाता है — वह त्याग सात्त्विक माना गया है।", english: "O Arjuna, when one performs his prescribed duty only because it ought to be done, and renounces all material association and all attachment to the fruit, his renunciation is said to be in the mode of goodness.", themes: ["Sattvic Renunciation", "Duty", "Non-attachment", "Best Renunciation"] },
  { chapterId: 18, id: 10, chapterName: "Liberation through Renunciation", skt: "न द्वेष्ट्यकुशलं कर्म कुशले नानुषज्जते।\nत्यागी सत्त्वसमाविष्टो मेधावी छिन्नसंशयः॥", iast: "na dveṣṭy akuśalaṃ karma kuśale nānuṣajjate\ntyāgī sattvasamāviṣṭo medhāvī chinnasaṃśayaḥ", hindi: "जो अकुशल कर्म से द्वेष नहीं करता और कुशल में आसक्त नहीं होता — वह सत्त्व से युक्त, मेधावी और संशयरहित त्यागी है।", english: "The intelligent renouncer situated in the mode of goodness, who neither hates inauspicious work nor is attached to auspicious work, has no doubts about work.", themes: ["True Renouncer", "Sattva", "No Doubt", "Equanimity"] },
  { chapterId: 18, id: 11, chapterName: "Liberation through Renunciation", skt: "न हि देहभृता शक्यं त्यक्तुं कर्माण्यशेषतः।\nयस्तु कर्मफलत्यागी स त्यागीत्यभिधीयते॥", iast: "na hi dehabhṛtā śakyaṃ tyaktuṃ karmāṇy aśeṣataḥ\nyas tu karmaphalatyāgī sa tyāgīty abhidhīyate", hindi: "शरीरधारी के लिए कर्मों को पूर्णतः त्यागना सम्भव नहीं है। जो कर्मफल का त्याग करता है — वह त्यागी कहलाता है।", english: "It is indeed impossible for an embodied being to give up all activities. But he who renounces the fruits of action is called one who has truly renounced.", themes: ["Impossible to Not Act", "Renounce Fruits", "True Renunciation", "Embodied Soul"] },
  { chapterId: 18, id: 12, chapterName: "Liberation through Renunciation", skt: "अनिष्टमिष्टं मिश्रं च त्रिविधं कर्मणः फलम्।\nभवत्यत्यागिनां प्रेत्य न तु संन्यासिनां क्वचित्॥", iast: "aniṣṭam iṣṭaṃ miśraṃ ca trividhaṃ karmaṇaḥ phalam\nbhavaty atyāgināṃ pretya na tu saṃnyāsināṃ kvacit", hindi: "त्याग न करने वालों को मृत्यु के बाद अनिष्ट, इष्ट और मिश्रित — तीन प्रकार का कर्मफल मिलता है। संन्यासियों को कहीं (किसी भी काल में) नहीं।", english: "For one who is not renounced, the threefold fruits of action — desirable, undesirable, and mixed — accrue after death. But those who are in the renounced order of life have no such result to suffer or enjoy.", themes: ["Three Fruits", "Renounced Order", "No Fruit", "After Death"] },
  { chapterId: 18, id: 13, chapterName: "Liberation through Renunciation", skt: "पञ्चैतानि महाबाहो कारणानि निबोध मे।\nसाङ्ख्ये कृतान्ते प्रोक्तानि सिद्धये सर्वकर्मणाम्॥", iast: "pañcaitāni mahābāho kāraṇāni nibodha me\nsāṃkhye kṛtānte proktāni siddhaye sarvakarmāṇām", hindi: "हे महाबाहो! सांख्यशास्त्र में सम्पूर्ण कर्मों की सिद्धि के लिए जो पाँच कारण कहे गए हैं — उन्हें मुझसे जानो।", english: "O mighty-armed Arjuna, according to the Vedanta there are five causes for the accomplishment of all action. Now learn of these from Me.", themes: ["Five Causes", "Vedanta", "Action", "Sankhya"] },
  { chapterId: 18, id: 14, chapterName: "Liberation through Renunciation", skt: "अधिष्ठानं तथा कर्ता करणं च पृथग्विधम्।\nविविधाश्च पृथक्चेष्टा दैवं चैवात्र पञ्चमम्॥", iast: "adhiṣṭhānaṃ tathā kartā karaṇaṃ ca pṛthagvidham\nvividhāś ca pṛthak ceṣṭā daivaṃ caivātra pañcamam", hindi: "अधिष्ठान (शरीर), कर्ता (जीव), विभिन्न करण (इन्द्रियाँ), विविध पृथक् चेष्टाएँ और पाँचवाँ दैव (भाग्य) — ये पाँच कारण हैं।", english: "The place of action, the performer, the various senses, the many different kinds of endeavor, and ultimately the Supersoul — these are the five factors of action.", themes: ["Five Factors", "Body", "Doer", "Senses", "Fate"] },
  { chapterId: 18, id: 15, chapterName: "Liberation through Renunciation", skt: "शरीरवाङ्मनोभिर्यत्कर्म प्रारभते नरः।\nन्याय्यं वा विपरीतं वा पञ्चैते तस्य हेतवः॥", iast: "śarīravāṃmanobhir yat karma prārabhate naraḥ\nnāyyaṃ vā viparītaṃ vā pañcaite tasya hetavaḥ", hindi: "मनुष्य शरीर, वाणी और मन से जो न्याय या विपरीत कर्म प्रारम्भ करता है — उसके ये पाँच ही हेतु हैं।", english: "Whatever right or wrong action a man performs by body, mind, or speech is caused by these five factors.", themes: ["Body-Speech-Mind", "Five Causes", "Action", "Responsibility"] },
  { chapterId: 18, id: 16, chapterName: "Liberation through Renunciation", skt: "तत्रैवं सति कर्तारमात्मानं केवलं तु यः।\nपश्यत्यकृतबुद्धित्वान्न स पश्यति दुर्मतिः॥", iast: "tatraivaṃ sati kartāram ātmānaṃ kevalaṃ tu yaḥ\npaśyaty akṛtabuddhitvān na sa paśyati durmatiḥ", hindi: "इस प्रकार होने पर भी जो अशुद्ध बुद्धि वाला दुर्मति केवल शुद्ध आत्मा को ही कर्ता देखता है — वह वास्तव में नहीं देखता।", english: "Therefore, one who thinks himself the only doer, not considering the five factors, is certainly not very intelligent and cannot see things as they are.", themes: ["Ignorance of Doership", "False Ego", "Wrong Vision", "Dull Intelligence"] },
  { chapterId: 18, id: 17, chapterName: "Liberation through Renunciation", skt: "यस्य नाहङ्कृतो भावो बुद्धिर्यस्य न लिप्यते।\nहत्वापि स इमाँल्लोकान्न हन्ति न निबध्यते॥", iast: "yasya nāhaṃkṛto bhāvo buddhir yasya na lipyate\nhatvāpi sa imāṃl lokān na hanti na nibadhyate", hindi: "जिसके अहंकार का भाव नहीं है और जिसकी बुद्धि लिप्त नहीं होती — वह इन सम्पूर्ण लोकों को मारकर भी न मारता है और न बँधता है।", english: "One who is not motivated by false ego, whose intelligence is not entangled, though he kills men in this world, does not kill. Nor is he bound by his actions.", themes: ["No Ego", "Not Bound", "True Non-doer", "Liberation"] },
  { chapterId: 18, id: 18, chapterName: "Liberation through Renunciation", skt: "ज्ञानं ज्ञेयं परिज्ञाता त्रिविधा कर्मचोदना।\nकरणं कर्म कर्तेति त्रिविधः कर्मसङ्ग्रहः॥", iast: "jñānaṃ jñeyaṃ parijñātā trividhā karmacaodanā\nkaraṇaṃ karma karteti trividhaḥ karmasaṃgrahaḥ", hindi: "ज्ञान, ज्ञेय और परिज्ञाता — ये तीन कर्मप्रेरणा हैं। करण (इन्द्रिय), कर्म और कर्ता — यह तीन प्रकार का कर्मसङ्ग्रह है।", english: "Knowledge, the object of knowledge, and the knower are the three factors that motivate action; the senses, the work, and the doer are the three constituents of action.", themes: ["Threefold Knowledge", "Threefold Action", "Knower-Known-Knowledge"] },
  { chapterId: 18, id: 19, chapterName: "Liberation through Renunciation", skt: "ज्ञानं कर्म च कर्ता च त्रिधैव गुणभेदतः।\nप्रोच्यते गुणसङ्ख्याने यथावच्छृणु तान्यपि॥", iast: "jñānaṃ karma ca kartā ca tridhā eva guṇabhedataḥ\nrocyate guṇasaṃkhyāne yathāvac chṛṇu tāny api", hindi: "गुणसंख्यान में ज्ञान, कर्म और कर्ता भी गुण के भेद से तीन-तीन प्रकार के कहे जाते हैं। उन्हें भी यथावत् सुनो।", english: "In accordance with the three modes of material nature, there are three kinds of knowledge, action, and performer of action. Listen as I describe these.", themes: ["Three Types", "Knowledge", "Action", "Doer", "Gunas"] },
  { chapterId: 18, id: 20, chapterName: "Liberation through Renunciation", skt: "सर्वभूतेषु येनैकं भावमव्ययमीक्षते।\nअविभक्तं विभक्तेषु तज्ज्ञानं विद्धि सात्त्विकम्॥", iast: "sarvabhūteṣu yenaikaṃ bhāvam avyayam īkṣate\navibhaktaṃ vibhakteṣu taj jñānaṃ viddhi sāttivikam", hindi: "जिस ज्ञान से सब भूतों में एक अव्यय भाव को — विभक्त में अविभक्त को — देखता है, उस ज्ञान को सात्त्विक जानो।", english: "That knowledge by which one undivided spiritual nature is seen in all living entities, though they are divided into innumerable forms, you should understand to be in the mode of goodness.", themes: ["Sattvic Knowledge", "Unity in Diversity", "Undivided", "Goodness"] },
  { chapterId: 18, id: 21, chapterName: "Liberation through Renunciation", skt: "पृथक्त्वेन तु यज्ज्ञानं नानाभावान्पृथग्विधान्।\nवेत्ति सर्वेषु भूतेषु तज्ज्ञानं विद्धि राजसम्॥", iast: "pṛthaktvena tu yaj jñānaṃ nānābhāvān pṛthagvidhān\nvetti sarveṣu bhūteṣu taj jñānaṃ viddhi rājasam", hindi: "जो ज्ञान सब भूतों में पृथक्-पृथक् अनेक भावों को जानता है — उस ज्ञान को राजस जानो।", english: "That knowledge by which one sees that in every different body there is a different type of living entity you should understand to be in the mode of passion.", themes: ["Rajasic Knowledge", "Seeing Multiplicity", "Passion", "Separate Beings"] },
  { chapterId: 18, id: 22, chapterName: "Liberation through Renunciation", skt: "यत्तु कृत्स्नवदेकस्मिन्कार्ये सक्तमहैतुकम्।\nअतत्त्वार्थवदल्पं च तत्तामसमुदाहृतम्॥", iast: "yat tu kṛtsnavad ekasmin kārye saktam ahaitukam\natattvārthavad alpaṃ ca tat tāmasam udāhṛtam", hindi: "जो एक कार्य में सम्पूर्ण के समान आसक्त, हेतुरहित, तत्त्वार्थरहित और तुच्छ है — वह तामस कहा जाता है।", english: "And that knowledge by which one is attached to one kind of work as the all in all, without knowledge of the truth, and which is very meager, is said to be in the mode of darkness.", themes: ["Tamasic Knowledge", "Narrow View", "Ignorance", "Attached to One Thing"] },
  { chapterId: 18, id: 23, chapterName: "Liberation through Renunciation", skt: "नियतं सङ्गरहितमरागद्वेषतः कृतम्।\nअफलप्रेप्सुना कर्म यत्तत्सात्त्विकमुच्यते॥", iast: "niyataṃ saṃgarahitam arāgadveṣataḥ kṛtam\naphalaprepsuunā karma yat tat sāttvikam ucyate", hindi: "जो नियत, आसक्तिरहित, राग-द्वेषरहित और फल की इच्छारहित पुरुष द्वारा किया जाता है — वह कर्म सात्त्विक कहलाता है।", english: "That action which is regulated and which is performed without attachment, without love or hatred, and without desire for fruitive results is said to be in the mode of goodness.", themes: ["Sattvic Action", "Regulated", "No Attachment", "No Desire"] },
  { chapterId: 18, id: 24, chapterName: "Liberation through Renunciation", skt: "यत्तु कामेप्सुना कर्म साहङ्कारेण वा पुनः।\nक्रियते बहुलायासं तद्राजसमुदाहृतम्॥", iast: "yat tu kāmepsunā karma sāhaṃkāreṇa vā punaḥ\nkriyate bahulāyāsaṃ tad rājasam udāhṛtam", hindi: "जो कर्म कामी द्वारा, अहंकार से या बड़े कष्ट से किया जाता है — वह राजस कहा जाता है।", english: "But action performed with great effort by one who seeks to gratify his desires, and enacted from a sense of false ego, is called action in the mode of passion.", themes: ["Rajasic Action", "Ego", "With Effort", "Desire for Results"] },
  { chapterId: 18, id: 25, chapterName: "Liberation through Renunciation", skt: "अनुबन्धं क्षयं हिंसामनपेक्ष्य च पौरुषम्।\nमोहादारभ्यते कर्म यत्तत्तामसमुच्यते॥", iast: "anubandhaṃ kṣayaṃ hiṃsām anapekṣya ca pauruṣam\nmohād ārabhyate karma yat tat tāmasam ucyate", hindi: "जो कर्म परिणाम, हानि, हिंसा और मनुष्यशक्ति की परवाह न करके मोह से प्रारम्भ किया जाता है — वह तामस कहलाता है।", english: "That action performed in illusion, in disregard of scriptural injunctions, and without concern for future bondage or for violence or distress caused to others is said to be in the mode of ignorance.", themes: ["Tamasic Action", "Ignorance", "Harm to Others", "Delusion"] },
  { chapterId: 18, id: 26, chapterName: "Liberation through Renunciation", skt: "मुक्तसङ्गोऽनहंवादी धृत्युत्साहसमन्वितः।\nसिद्ध्यसिद्ध्योर्निर्विकारः कर्ता सात्त्विक उच्यते॥", iast: "muktasaṃgo'nahaṃvādī dhṛty utsāhasamanvitaḥ\nsiddhyasiddhyor nirvikāraḥ kartā sāttivika ucyate", hindi: "आसक्तिरहित, 'मैं' न कहने वाला, धैर्य और उत्साह से युक्त, सिद्धि-असिद्धि में विकाररहित कर्ता सात्त्विक कहलाता है।", english: "One who performs his duty without association with the modes of material nature, without false ego, with great determination and enthusiasm, and without wavering in success or failure is said to be a worker in the mode of goodness.", themes: ["Sattvic Doer", "No Ego", "Enthusiasm", "Equanimity"] },
  { chapterId: 18, id: 27, chapterName: "Liberation through Renunciation", skt: "रागी कर्मफलप्रेप्सुर्लुब्धो हिंसात्मकोऽशुचिः।\nहर्षशोकान्वितः कर्ता राजसः परिकीर्तितः॥", iast: "rāgī karmaphalaprepsur lubdho hiṃsātmako'śuciḥ\nharṣaśokānvitaḥ kartā rājasaḥ parikīrtitaḥ", hindi: "आसक्त, कर्मफल की इच्छा वाला, लोभी, हिंसात्मक, अशुद्ध और हर्ष-शोक से युक्त कर्ता राजस कहलाता है।", english: "The worker who is attached to work and the fruits of work, desiring to enjoy those fruits, and who is greedy, always envious, impure, and moved by joy and sorrow, is said to be in the mode of passion.", themes: ["Rajasic Doer", "Attached", "Greedy", "Impure"] },
  { chapterId: 18, id: 28, chapterName: "Liberation through Renunciation", skt: "अयुक्तः प्राकृतः स्तब्धः शठो नैष्कृतिकोऽलसः।\nविषादी दीर्घसूत्री च कर्ता तामस उच्यते॥", iast: "ayuktaḥ prākṛtaḥ stabdhaḥ śaṭho naiṣkṛtiko'lasaḥ\nviṣādī dīrghasūtrī ca kartā tāmasa ucyate", hindi: "अयुक्त, अशिक्षित, हठी, शठ, दूसरों की आजीविका लेने वाला, आलसी, विषादग्रस्त और दीर्घसूत्री कर्ता तामस कहलाता है।", english: "The worker who is always engaged in work against the injunctions of the scripture, who is materialistic, obstinate, cheating, and expert in insulting others, and who is lazy, always morose, and procrastinating is said to be a worker in the mode of ignorance.", themes: ["Tamasic Doer", "Lazy", "Obstinate", "Procrastinating"] },
  { chapterId: 18, id: 29, chapterName: "Liberation through Renunciation", skt: "बुद्धेर्भेदं धृतेश्चैव गुणतस्त्रिविधं शृणु।\nप्रोच्यमानमशेषेण पृथक्त्वेन धनञ्जय॥", iast: "buddher bhedaṃ dhṛteś caiva guṇatas trividhaṃ śṛṇu\nprocyamānam aśeṣeṇa pṛthaktvena dhanañjaya", hindi: "हे धनञ्जय! बुद्धि और धृति के गुणों के अनुसार तीन-तीन प्रकार के भेद — पृथक्-पृथक् विस्तार से कहे जा रहे हैं — सुनो।", english: "O winner of wealth, now please listen as I tell you in detail of the different kinds of understanding and determination, according to the three modes of material nature.", themes: ["Three Types of Intelligence", "Determination", "Gunas", "Teaching"] },
  { chapterId: 18, id: 30, chapterName: "Liberation through Renunciation", skt: "प्रवृत्तिं च निवृत्तिं च कार्याकार्ये भयाभये।\nबन्धं मोक्षं च या वेत्ति बुद्धिः सा पार्थ सात्त्विकी॥", iast: "pravṛttiṃ ca nivṛttiṃ ca kāryākārye bhayābhaye\nbandhaṃ mokṣaṃ ca yā vetti buddhiḥ sā pārtha sāttvikī", hindi: "हे पार्थ! जो बुद्धि प्रवृत्ति और निवृत्ति, कार्य और अकार्य, भय और अभय तथा बन्धन और मोक्ष को जानती है — वह सात्त्विकी है।", english: "O son of Pritha, that understanding by which one knows what ought to be done and what ought not to be done, what is to be feared and what is not to be feared, what is binding and what is liberating, is in the mode of goodness.", themes: ["Sattvic Intelligence", "Right-Wrong", "Fear-Fearlessness", "Bondage-Liberation"] },
  { chapterId: 18, id: 31, chapterName: "Liberation through Renunciation", skt: "यया धर्ममधर्मं च कार्यं चाकार्यमेव च।\nअयथावत्प्रजानाति बुद्धिः सा पार्थ राजसी॥", iast: "yayā dharmam adharmaṃ ca kāryaṃ cākāryam eva ca\nayathāvat prajānāti buddhiḥ sā pārtha rājasī", hindi: "हे पार्थ! जो बुद्धि धर्म-अधर्म और कार्य-अकार्य को ठीक से नहीं जानती — वह राजसी है।", english: "O son of Pritha, that understanding which cannot distinguish between religion and irreligion, between action that should be done and action that should not be done, is in the mode of passion.", themes: ["Rajasic Intelligence", "Confused", "Dharma-Adharma", "Passion"] },
  { chapterId: 18, id: 32, chapterName: "Liberation through Renunciation", skt: "अधर्मं धर्ममिति या मन्यते तमसावृता।\nसर्वार्थान्विपरीतांश्च बुद्धिः सा पार्थ तामसी॥", iast: "adharmaṃ dharmam iti yā manyate tamasāvṛtā\nsarvārthān viparītāṃś ca buddhiḥ sā pārtha tāmasī", hindi: "हे पार्थ! तम से ढकी हुई जो बुद्धि अधर्म को धर्म और सभी अर्थों को उलटा मानती है — वह तामसी है।", english: "That understanding which considers irreligion to be religion and religion to be irreligion, under the spell of illusion and darkness, and strives always in the wrong direction, O Partha, is in the mode of ignorance.", themes: ["Tamasic Intelligence", "Wrong View", "Illusion", "Adharma as Dharma"] },
  { chapterId: 18, id: 33, chapterName: "Liberation through Renunciation", skt: "धृत्या यया धारयते मनःप्राणेन्द्रियक्रियाः।\nयोगेनाव्यभिचारिण्या धृतिः सा पार्थ सात्त्विकी॥", iast: "dhṛtyā yayā dhārayate manaḥprāṇendriyakriyāḥ\nyogenāvyabhicāriṇyā dhṛtiḥ sā pārtha sāttvikī", hindi: "हे पार्थ! जिस धृति (दृढ़ता) से योग के द्वारा अव्यभिचारी मन, प्राण और इन्द्रियों की क्रियाओं को धारण किया जाता है — वह धृति सात्त्विकी है।", english: "O son of Pritha, that determination which is unbreakable, which is sustained with steadfastness by yoga practice, and which thus controls the activities of the mind, life, and senses is determination in the mode of goodness.", themes: ["Sattvic Determination", "Unbreakable", "Yoga", "Mind-Prana-Senses"] },
  { chapterId: 18, id: 34, chapterName: "Liberation through Renunciation", skt: "यया तु धर्मकामार्थान्धृत्या धारयतेऽर्जुन।\nप्रसङ्गेन फलाकाङ्क्षी धृतिः सा पार्थ राजसी॥", iast: "yayā tu dharmakāmārthān dhṛtyā dhārayate'rjuna\nprasaṃgena phalākāṅkṣī dhṛtiḥ sā pārtha rājasī", hindi: "हे पार्थ! जिस धृति से फलाकांक्षी धर्म, काम और अर्थ को आसक्ति से धारण करता है — वह धृति राजसी है।", english: "But that determination by which one holds fast to fruitive results in religion, economic development, and sense gratification is of the nature of passion, O Arjuna.", themes: ["Rajasic Determination", "Fruitive", "Dharma-Artha-Kama", "Passion"] },
  { chapterId: 18, id: 35, chapterName: "Liberation through Renunciation", skt: "यया स्वप्नं भयं शोकं विषादं मदमेव च।\nन विमुञ्चति दुर्मेधा धृतिः सा पार्थ तामसी॥", iast: "yayā svapnaṃ bhayaṃ śokaṃ viṣādaṃ madam eva ca\nna vimuñcati durmedhā dhṛtiḥ sā pārtha tāmasī", hindi: "हे पार्थ! जिस धृति से दुर्मेधा मनुष्य नींद, भय, शोक, विषाद और अहंकार को नहीं छोड़ता — वह तामसी है।", english: "And that determination which cannot go beyond dreaming, fearfulness, lamentation, moroseness, and illusion — such unintelligent determination, O son of Pritha, is in the mode of darkness.", themes: ["Tamasic Determination", "Sleep", "Fear", "Grief", "Ignorance"] },
  { chapterId: 18, id: 36, chapterName: "Liberation through Renunciation", skt: "सुखं त्विदानीं त्रिविधं शृणु मे भरतर्षभ।\nअभ्यासाद्रमते यत्र दुःखान्तं च निगच्छति॥", iast: "sukhaṃ tv idānīṃ trividhaṃ śṛṇu me bharatarṣabha\nabhyāsād ramate yatra duḥkhāntaṃ ca nigacchati", hindi: "हे भरतर्षभ! अब तीन प्रकार के सुख को सुनो — जिसमें अभ्यास से रमण होता है और जो दुःखों का अन्त करता है।", english: "O best of the Bharatas, now please hear from Me about the three kinds of happiness by which the conditioned soul enjoys, and by which he sometimes comes to the end of all distress.", themes: ["Three Kinds of Happiness", "Pleasure", "End of Suffering", "Teaching"] },
  { chapterId: 18, id: 37, chapterName: "Liberation through Renunciation", skt: "यत्तदग्रे विषमिव परिणामेऽमृतोपमम्।\nतत्सुखं सात्त्विकं प्रोक्तमात्मबुद्धिप्रसादजम्॥", iast: "yat tad agre viṣam iva pariṇāme'mṛtopamam\ntat sukhaṃ sāttvikaṃ proktam ātmabuddhiprasādajam", hindi: "जो सुख पहले विष के समान लगे किन्तु परिणाम में अमृत के समान हो — वह आत्मबुद्धि-प्रसाद से उत्पन्न सुख सात्त्विक कहलाता है।", english: "That which in the beginning may be just like poison but at the end is just like nectar and which awakens one to self-realization is said to be happiness in the mode of goodness.", themes: ["Sattvic Happiness", "Difficult Start-Sweet End", "Self-realization", "Nectar"] },
  { chapterId: 18, id: 38, chapterName: "Liberation through Renunciation", skt: "विषयेन्द्रियसंयोगाद्यत्तदग्रेऽमृतोपमम्।\nपरिणामे विषमिव तत्सुखं राजसं स्मृतम्॥", iast: "viṣayendriyasaṃyogād yat tad agre'mṛtopamam\npariṇāme viṣam iva tat sukhaṃ rājasaṃ smṛtam", hindi: "जो सुख विषय और इन्द्रिय के संयोग से पहले अमृत के समान लगे और परिणाम में विष के समान हो — वह राजस कहलाता है।", english: "That happiness which is derived from contact of the senses with their objects and which appears like nectar at first but poison at the end is said to be of the nature of passion.", themes: ["Rajasic Happiness", "Sense Pleasure", "Sweet Start-Bitter End", "Passion"] },
  { chapterId: 18, id: 39, chapterName: "Liberation through Renunciation", skt: "यदग्रे चानुबन्धे च सुखं मोहनमात्मनः।\nनिद्रालस्यप्रमादोत्थं तत्तामसमुदाहृतम्॥", iast: "yad agre cānubandhe ca sukhaṃ mohanam ātmanaḥ\nnidrālasyapramādotthaṃ tat tāmasam udāhṛtam", hindi: "जो सुख पहले और परिणाम में आत्मा को मोहित करने वाला हो, निद्रा, आलस्य और प्रमाद से उत्पन्न हो — वह तामस कहा जाता है।", english: "And that happiness which is blind to self-realization, which is delusion from beginning to end and which arises from sleep, laziness, and illusion is said to be of the nature of ignorance.", themes: ["Tamasic Happiness", "Delusion", "Sleep", "Laziness"] },
  { chapterId: 18, id: 40, chapterName: "Liberation through Renunciation", skt: "न तदस्ति पृथिव्यां वा दिवि देवेषु वा पुनः।\nसत्त्वं प्रकृतिजैर्मुक्तं यदेभिः स्यात्त्रिभिर्गुणैः॥", iast: "na tad asti pṛthivyāṃ vā divi deveṣu vā punaḥ\nsattvaṃ prakṛtijair muktaṃ yad ebhiḥ syāt tribhir guṇaiḥ", hindi: "पृथ्वी में, स्वर्ग में या देवताओं में — ऐसा कोई भी सत्त्व नहीं है जो प्रकृति से उत्पन्न इन तीन गुणों से मुक्त हो।", english: "There is no being existing, either here or among the demigods in the higher planetary systems, which is freed from these three modes born of material nature.", themes: ["Three Gunas Universal", "No Escape in Creation", "Material World", "Gunas"] },
  { chapterId: 18, id: 41, chapterName: "Liberation through Renunciation", skt: "ब्राह्मणक्षत्रियविशां शूद्राणां च परन्तप।\nकर्माणि प्रविभक्तानि स्वभावप्रभवैर्गुणैः॥", iast: "brāhmaṇakṣatriyaviśāṃ śūdrāṇāṃ ca paraṃtapa\nkarmāṇi pravibhaktāni svabhāvaprabhavair guṇaiḥ", hindi: "हे परन्तप! ब्राह्मण, क्षत्रिय, वैश्य और शूद्रों के कर्म स्वभाव से उत्पन्न गुणों के अनुसार विभाजित हैं।", english: "Brahmanas, kshatriyas, vaishyas, and shudras are distinguished by their qualities of work, O chastiser of the enemy, in accordance with the modes of nature.", themes: ["Varna System", "Natural Qualities", "Duties", "Social Order"] },
  { chapterId: 18, id: 42, chapterName: "Liberation through Renunciation", skt: "शमो दमस्तपः शौचं क्षान्तिरार्जवमेव च।\nज्ञानं विज्ञानमास्तिक्यं ब्रह्मकर्म स्वभावजम्॥", iast: "śamo damas tapaḥ śaucaṃ kṣāntir ārjavam eva ca\njñānaṃ vijñānam āstikyaṃ brahmakarma svabhāvajam", hindi: "शम, दम, तप, शुचिता, क्षमा, सरलता, ज्ञान, विज्ञान और आस्तिकता — ये ब्राह्मण के स्वभावजन्य कर्म हैं।", english: "Peacefulness, self-control, austerity, purity, tolerance, honesty, knowledge, wisdom, and religiousness — these are the natural qualities by which the brahmanas work.", themes: ["Brahmin Duties", "Knowledge", "Austerity", "Purity"] },
  { chapterId: 18, id: 43, chapterName: "Liberation through Renunciation", skt: "शौर्यं तेजो धृतिर्दाक्ष्यं युद्धे चाप्यपलायनम्।\nदानमीश्वरभावश्च क्षात्रं कर्म स्वभावजम्॥", iast: "śauryaṃ tejo dhṛtir dākṣyaṃ yuddhe cāpy apalāyanam\ndānam īśvarabhāvaś ca kṣātraṃ karma svabhāvajam", hindi: "शौर्य, तेज, धैर्य, दक्षता, युद्ध में न भागना, दान और स्वामित्व का भाव — ये क्षत्रिय के स्वभावजन्य कर्म हैं।", english: "Heroism, power, determination, resourcefulness, courage in battle, generosity, and leadership are the natural qualities of work for the kshatriyas.", themes: ["Kshatriya Duties", "Heroism", "Courage", "Leadership"] },
  { chapterId: 18, id: 44, chapterName: "Liberation through Renunciation", skt: "कृषिगौरक्ष्यवाणिज्यं वैश्यकर्म स्वभावजम्।\nपरिचर्यात्मकं कर्म शूद्रस्यापि स्वभावजम्॥", iast: "kṛṣigaurakṣyavāṇijyaṃ vaiśyakarma svabhāvajam\nparicaryātmakaṃ karma śūdrasyāpi svabhāvajam", hindi: "कृषि, गोपालन और वाणिज्य — ये वैश्य के स्वभावजन्य कर्म हैं। सेवा करना — यह शूद्र का स्वभावजन्य कर्म है।", english: "Farming, cow protection, and business are the natural work for the vaishyas, and for the shudras there are labor and service to others.", themes: ["Vaishya Duties", "Shudra Duties", "Service", "Agriculture"] },
  { chapterId: 18, id: 45, chapterName: "Liberation through Renunciation", skt: "स्वे स्वे कर्मण्यभिरतः संसिद्धिं लभते नरः।\nस्वकर्मनिरतः सिद्धिं यथा विन्दति तच्छृणु॥", iast: "sve sve karmaṇy abhirataḥ saṃsiddhiṃ labhate naraḥ\nsvakarmaniratah siddhiṃ yathā vindati tac chṛṇu", hindi: "अपने-अपने कर्म में लगा हुआ मनुष्य संसिद्धि प्राप्त करता है। अपने कर्म में लगा हुआ कैसे सिद्धि पाता है — सुनो।", english: "By following his qualities of work, every man can become perfect. Now please hear from Me how this can be done.", themes: ["Own Duty", "Perfection", "Natural Work", "Success"] },
  { chapterId: 18, id: 46, chapterName: "Liberation through Renunciation", skt: "यतः प्रवृत्तिर्भूतानां येन सर्वमिदं ततम्।\nस्वकर्मणा तमभ्यर्च्य सिद्धिं विन्दति मानवः॥", iast: "yataḥ pravṛttir bhūtānāṃ yena sarvam idaṃ tatam\nsvakarmaNā tam abhyarcya siddhiṃ vindati mānavaḥ", hindi: "जिससे सभी प्राणियों की प्रवृत्ति है और जिसने यह सब व्याप्त किया है — अपने कर्म से उसकी पूजा करके मनुष्य सिद्धि पाता है।", english: "By worship of the Lord, who is the source of all beings and who is all-pervading, man can, in the performance of his own duty, attain perfection.", themes: ["Worship Through Work", "God as Source", "Perfection", "Duty"] },
  { chapterId: 18, id: 47, chapterName: "Liberation through Renunciation", skt: "श्रेयान्स्वधर्मो विगुणः परधर्मात्स्वनुष्ठितात्।\nस्वभावनियतं कर्म कुर्वन्नाप्नोति किल्बिषम्॥", iast: "śreyān svadharmo viguṇaḥ paradharmāt svanuṣṭhitāt\nsvabhāvaniyataṃ karma kurvan nāpnoti kilbiṣam", hindi: "सम्यक् पालित परधर्म से गुणरहित स्वधर्म श्रेष्ठ है। स्वभाव से नियत कर्म करने से पाप नहीं लगता।", english: "It is better to engage in one's own occupation, even though one may perform it imperfectly, than to accept another's occupation and perform it perfectly. Duties prescribed according to one's nature are never affected by sinful reactions.", themes: ["Own Duty Best", "Svadharma", "No Sin", "Natural Work"] },
  { chapterId: 18, id: 48, chapterName: "Liberation through Renunciation", skt: "सहजं कर्म कौन्तेय सदोषमपि न त्यजेत्।\nसर्वारम्भा हि दोषेण धूमेनाग्निरिवावृताः॥", iast: "sahajaṃ karma kaunteya sadoṣam api na tyajet\nsarvārambhā hi doṣeṇa dhūmenāgnir ivāvṛtāḥ", hindi: "हे कौन्तेय! सहज (स्वाभाविक) कर्म दोषयुक्त होने पर भी नहीं त्यागना चाहिए। जैसे अग्नि धुएँ से ढकी होती है, वैसे सभी कर्म दोष से ढके होते हैं।", english: "Every endeavor is covered by some fault, just as fire is covered by smoke. Therefore one should not give up the work born of his nature, O son of Kunti, even if such work is full of fault.", themes: ["Natural Work Has Faults", "Fire-Smoke Analogy", "Not to Abandon", "Own Duty"] },
  { chapterId: 18, id: 49, chapterName: "Liberation through Renunciation", skt: "असक्तबुद्धिः सर्वत्र जितात्मा विगतस्पृहः।\nनैष्कर्म्यसिद्धिं परमां संन्यासेनाधिगच्छति॥", iast: "asaktabuddhiḥ sarvatra jitātmā vigatas spṛhaḥ\nnaiṣkarmyasiddhiṃ paramāṃ saṃnyāsenādhigacchati", hindi: "सर्वत्र अनासक्त बुद्धि, जितात्मा और स्पृहारहित पुरुष संन्यास से नैष्कर्म्य की परम सिद्धि को प्राप्त होता है।", english: "One who is self-controlled and unattached and who disregards all material enjoyments can obtain, by practice of renunciation, the highest perfect stage of freedom from reaction.", themes: ["Non-attachment", "Self-control", "Naishkarmya", "Renunciation"] },
  { chapterId: 18, id: 50, chapterName: "Liberation through Renunciation", skt: "सिद्धिं प्राप्तो यथा ब्रह्म तथाप्नोति निबोध मे।\nसमासेनैव कौन्तेय निष्ठा ज्ञानस्य या परा॥", iast: "siddhiṃ prāpto yathā brahma tathāpnoti nibodha me\nsamāsenaiva kaunteya niṣṭhā jñānasya yā parā", hindi: "हे कौन्तेय! सिद्धि प्राप्त करके जो ब्रह्म को प्राप्त होता है — उस ज्ञान की परम निष्ठा को मुझसे संक्षेप में जानो।", english: "O son of Kunti, learn from Me how one who has achieved this perfection can attain to the supreme perfectional stage, Brahman, the stage of highest knowledge, by acting in the way I shall now summarize.", themes: ["How to Attain Brahman", "Perfection", "Knowledge", "Path"] },
  { chapterId: 18, id: 51, chapterName: "Liberation through Renunciation", skt: "बुद्ध्या विशुद्धया युक्तो धृत्यात्मानं नियम्य च।\nशब्दादीन्विषयांस्त्यक्त्वा रागद्वेषौ व्युदस्य च॥", iast: "buddhyā viśuddhayā yukto dhṛtyātmānaṃ niyamya ca\nśabdādīn viṣayāṃs tyaktvā rāgadveṣau vyudasya ca", hindi: "विशुद्ध बुद्धि से युक्त, धैर्य से आत्मनिग्रह करके, शब्दादि विषयों को त्यागकर और राग-द्वेष को दूर करके।", english: "Being purified by his intelligence and controlling the mind with determination, giving up the objects of sense gratification, being freed from attachment and hatred —", themes: ["Pure Intelligence", "Sense Control", "No Attachment-Hatred", "Path to Brahman"] },
  { chapterId: 18, id: 52, chapterName: "Liberation through Renunciation", skt: "विविक्तसेवी लघ्वाशी यतवाक्कायमानसः।\nध्यानयोगपरो नित्यं वैराग्यं समुपाश्रितः॥", iast: "viviktasevī laghvāśī yatavākkāyamānasaḥ\ndhyānayogaparo nityaṃ vairāgyaṃ samupāśritaḥ", hindi: "एकान्त में रहने वाला, अल्पाहारी, वाणी-शरीर-मन को संयमित करने वाला, नित्य ध्यानयोग में तत्पर और वैराग्य का आश्रय लेने वाला।", english: "One who lives in a secluded place, who eats little, who controls his body, mind and power of speech, who is always in trance and who is detached —", themes: ["Solitude", "Moderation", "Meditation", "Detachment"] },
  { chapterId: 18, id: 53, chapterName: "Liberation through Renunciation", skt: "अहङ्कारं बलं दर्पं कामं क्रोधं परिग्रहम्।\nविमुच्य निर्ममः शान्तो ब्रह्मभूयाय कल्पते॥", iast: "ahaṃkāraṃ balaṃ darpaṃ kāmaṃ krodhaṃ parigraham\nvimucya nirmamaḥ śānto brahmabhūyāya kalpate", hindi: "अहंकार, बल, दर्प, काम, क्रोध और परिग्रह को त्यागकर, ममतारहित और शान्त होकर ब्रह्मभाव के योग्य होता है।", english: "Free from ego, false strength, false pride, lust, anger, and acceptance of material things; free from false proprietorship; and peaceful — such a person is certainly elevated to the position of self-realization.", themes: ["Free from Ego", "Peace", "Brahman", "Liberation"] },
  { chapterId: 18, id: 54, chapterName: "Liberation through Renunciation", skt: "ब्रह्मभूतः प्रसन्नात्मा न शोचति न काङ्क्षति।\nसमः सर्वेषु भूतेषु मद्भक्तिं लभते पराम्॥", iast: "brahmabhūtaḥ prasannātmā na śocati na kāṅkṣati\nsamaḥ sarveṣu bhūteṣu madbhaktiṃ labhate parām", hindi: "ब्रह्मभूत प्रसन्नात्मा न शोक करता है, न इच्छा करता है। सभी प्राणियों में समान होकर मेरी परा भक्ति पाता है।", english: "One who is thus transcendentally situated at once realizes the Supreme Brahman and becomes fully joyful. He never laments nor desires to have anything. He is equally disposed to every living entity. In that state he attains pure devotional service unto Me.", themes: ["Brahman Realized", "Equal Vision", "Supreme Devotion", "Joy"] },
  { chapterId: 18, id: 55, chapterName: "Liberation through Renunciation", skt: "भक्त्या मामभिजानाति यावान्यश्चास्मि तत्त्वतः।\nततो मां तत्त्वतो ज्ञात्वा विशते तदनन्तरम्॥", iast: "bhaktyā mām abhijānāti yāvān yaś cāsmi tattvataḥ\ntato māṃ tattvato jñātvā viśate tad anantaram", hindi: "भक्ति से ही वह मुझे तत्त्व से जानता है — मैं कितना हूँ और कैसा हूँ। तत्त्व से मुझे जानकर तत्पश्चात् मुझमें प्रवेश करता है।", english: "One can understand Me as I am, as the Supreme Personality of Godhead, only by devotional service. And when one is in full consciousness of Me by such devotion, he can enter into the kingdom of God.", themes: ["Devotion as Only Way", "Knowing God", "Entering God", "Liberation"] },
  { chapterId: 18, id: 56, chapterName: "Liberation through Renunciation", skt: "सर्वकर्माण्यपि सदा कुर्वाणो मद्व्यपाश्रयः।\nमत्प्रसादादवाप्नोति शाश्वतं पदमव्ययम्॥", iast: "sarvakarmāṇy api sadā kurvāṇo madvyapāśrayaḥ\nmatprasādād avāpnoti śāśvataṃ padam avyayam", hindi: "सदा सब कर्म करते हुए भी मेरे आश्रय में रहने वाला मेरे प्रसाद से शाश्वत अव्यय पद पाता है।", english: "Though engaged in all kinds of activities, My pure devotee, under My protection, reaches the eternal and imperishable abode by My grace.", themes: ["God's Grace", "Eternal Abode", "Action", "Devotion"] },
  { chapterId: 18, id: 57, chapterName: "Liberation through Renunciation", skt: "चेतसा सर्वकर्माणि मयि संन्यस्य मत्परः।\nबुद्धियोगमुपाश्रित्य मच्चित्तः सततं भव॥", iast: "cetasā sarvakarmāṇi mayi saṃnyasya matparaḥ\nbuddhiyogam upāśritya maccittaḥ satataṃ bhava", hindi: "चेतना से सभी कर्म मुझ में अर्पण करके, मुझे परम मानकर, बुद्धियोग का आश्रय लेकर, सदा मुझ में चित्त रखो।", english: "In all activities just depend upon Me and work always under My protection. In such devotional service, be fully conscious of Me.", themes: ["Surrender", "God's Protection", "Mind on God", "Devotion"] },
  { chapterId: 18, id: 58, chapterName: "Liberation through Renunciation", skt: "मच्चित्तः सर्वदुर्गाणि मत्प्रसादात्तरिष्यसि।\nअथ चेत्त्वमहङ्कारान्न श्रोष्यसि विनङ्क्ष्यसि॥", iast: "maccittaḥ sarvadurgāṇi matprasādāt tariṣyasi\natha cet tvam ahaṃkārān na śroṣyasi vinaṃkṣyasi", hindi: "मुझ में चित्त रखकर मेरे प्रसाद से सभी कठिनाइयों को पार करोगे। यदि अहंकार से नहीं सुनोगे तो नष्ट होगे।", english: "If you become conscious of Me, you will pass over all the obstacles of conditioned life by My grace. If, however, you do not work in such consciousness but act through false ego, not hearing Me, you will be lost.", themes: ["God's Grace", "Crossing Difficulties", "Ego's Danger", "Warning"] },
  { chapterId: 18, id: 59, chapterName: "Liberation through Renunciation", skt: "यदहङ्कारमाश्रित्य न योत्स्य इति मन्यसे।\nमिथ्यैष व्यवसायस्ते प्रकृतिस्त्वां नियोक्ष्यति॥", iast: "yad ahaṃkāram āśritya na yotsya iti manyase\nmithyaiṣa vyavasāyas te prakṛtis tvāṃ niyokṣyati", hindi: "यदि अहंकार से 'मैं नहीं लड़ूँगा' ऐसा सोचते हो — यह निश्चय मिथ्या है। प्रकृति तुम्हें युद्ध में लगाएगी।", english: "If you do not act according to My direction and do not fight, then you will be falsely directed. By your nature, you will have to be engaged in warfare.", themes: ["Duty", "Nature", "Forced Action", "Arjuna"] },
  { chapterId: 18, id: 60, chapterName: "Liberation through Renunciation", skt: "स्वभावजेन कौन्तेय निबद्धः स्वेन कर्मणा।\nकर्तुं नेच्छसि यन्मोहात्करिष्यस्यवशोऽपि तत्॥", iast: "svabhāvajena kaunteya nibaddhaḥ svena karmaṇā\nkartuṃ necchasi yan mohāt kariṣyasy avaśo'pi tat", hindi: "हे कौन्तेय! अपने स्वभावजन्य कर्म से बँधे होने के कारण मोह से जो करना नहीं चाहते — वह परवश होकर करोगे।", english: "O son of Kunti, under illusion you are now declining to act according to My direction. But, compelled by the work born of your own nature, you will act all the same.", themes: ["Compulsion of Nature", "Duty", "Illusion", "Action"] },
  { chapterId: 18, id: 61, chapterName: "Liberation through Renunciation", skt: "ईश्वरः सर्वभूतानां हृद्देशेऽर्जुन तिष्ठति।\nभ्रामयन्सर्वभूतानि यन्त्रारूढानि मायया॥", iast: "īśvaraḥ sarvabhūtānāṃ hṛddeśe'rjuna tiṣṭhati\nbhrāmayan sarvabhūtāni yantrārūḍhāni māyayā", hindi: "हे अर्जुन! ईश्वर सभी प्राणियों के हृदय में स्थित है। माया से यंत्र पर चढ़े हुए सभी प्राणियों को घुमाता है।", english: "The Supreme Lord is situated in everyone's heart, O Arjuna, and is directing the wanderings of all living entities, who are seated as on a machine, made of the material energy.", themes: ["God in Heart", "Machine Analogy", "Maya", "Divine Direction"] },
  { chapterId: 18, id: 62, chapterName: "Liberation through Renunciation", skt: "तमेव शरणं गच्छ सर्वभावेन भारत।\nतत्प्रसादात्परां शान्तिं स्थानं प्राप्स्यसि शाश्वतम्॥", iast: "tam eva śaraṇaṃ gaccha sarvabhāvena bhārata\ntatprasādāt parāṃ śāntiṃ sthānaṃ prāpsyasi śāśvatam", hindi: "हे भारत! सर्वभाव से उसकी शरण जाओ। उसके प्रसाद से परम शान्ति और शाश्वत स्थान पाओगे।", english: "O scion of Bharata, surrender unto Him utterly. By His grace you will attain transcendental peace and the supreme and eternal abode.", themes: ["Surrender", "God's Grace", "Peace", "Eternal Abode"] },
  { chapterId: 18, id: 63, chapterName: "Liberation through Renunciation", skt: "इति ते ज्ञानमाख्यातं गुह्याद्गुह्यतरं मया।\nविमृश्यैतदशेषेण यथेच्छसि तथा कुरु॥", iast: "iti te jñānam ākhyātaṃ guhyād guhyataraṃ mayā\nvimṛśyaitad aśeṣeṇa yathecchasi tathā kuru", hindi: "इस प्रकार यह गुह्य से भी अधिक गुह्य ज्ञान मैंने तुम्हें कहा। इसे पूर्णतः विचार करके, जैसी तुम्हारी इच्छा हो — वैसा करो।", english: "Thus I have explained to you knowledge still more confidential. Deliberate on this fully, and then do what you wish to do.", themes: ["Free Will", "Reflection", "Choice", "Teaching Ends"] },
  { chapterId: 18, id: 64, chapterName: "Liberation through Renunciation", skt: "सर्वगुह्यतमं भूयः शृणु मे परमं वचः।\nइष्टोऽसि मे दृढमिति ततो वक्ष्यामि ते हितम्॥", iast: "sarvaguhyatamaṃ bhūyaḥ śṛṇu me paramaṃ vacaḥ\niṣṭo'si me dṛḍham iti tato vakṣyāmi te hitam", hindi: "सर्वाधिक गुह्य मेरे परम वचन को फिर सुनो। तुम मुझे दृढ़तापूर्वक प्रिय हो — इसलिए तुम्हारा हित कहूँगा।", english: "Because you are My very dear friend, I am speaking to you My supreme instruction, the most confidential knowledge of all. Hear this from Me, for it is for your benefit.", themes: ["Most Confidential", "God's Love", "Friendship", "Final Teaching"] },
  { chapterId: 18, id: 65, chapterName: "Liberation through Renunciation", skt: "मन्मना भव मद्भक्तो मद्याजी मां नमस्कुरु।\nमामेवैष्यसि सत्यं ते प्रतिजाने प्रियोऽसि मे॥", iast: "manmanā bhava madbhakto madyājī māṃ namaskuru\nmām evaiṣyasi satyaṃ te pratijāne priyo'si me", hindi: "मुझ में मन लगाओ, मेरे भक्त बनो, मुझे पूजो, मुझे नमस्कार करो। मुझे ही प्राप्त होगे — यह सत्य तुमसे प्रतिज्ञा करता हूँ। तुम मुझे प्रिय हो।", english: "Always think of Me, become My devotee, worship Me and offer your homage unto Me. Thus you will come to Me without fail. I promise you this because you are My very dear friend.", themes: ["Mind on God", "Devotion", "God's Promise", "Friendship"] },
  { chapterId: 18, id: 66, chapterName: "Liberation through Renunciation", skt: "सर्वधर्मान्परित्यज्य मामेकं शरणं व्रज।\nअहं त्वां सर्वपापेभ्यो मोक्षयिष्यामि मा शुचः॥", iast: "sarvadharmān parityajya mām ekaṃ śaraṇaṃ vraja\nahaṃ tvāṃ sarvapāpebhyo mokṣayiṣyāmi mā śucaḥ", hindi: "सभी धर्मों को त्यागकर मेरी एकमात्र शरण ग्रहण करो। मैं तुम्हें सभी पापों से मुक्त करूँगा — शोक मत करो।", english: "Abandon all varieties of religion and just surrender unto Me. I shall deliver you from all sinful reactions. Do not fear.", themes: ["Surrender", "God's Promise", "Liberation from Sin", "Fearlessness"] },
  { chapterId: 18, id: 67, chapterName: "Liberation through Renunciation", skt: "इदं ते नातपस्काय नाभक्ताय कदाचन।\nन चाशुश्रूषवे वाच्यं न च मां योऽभ्यसूयति॥", iast: "idaṃ te nātapaskāya nābhaktāya kadācana\nna cāśuśrūṣave vācyaṃ na ca māṃ yo'bhyasūyati", hindi: "यह (ज्ञान) तपस्यारहित को, अभक्त को, श्रवण न करने वाले को और जो मुझसे ईर्ष्या करे — उसे कभी नहीं बताना चाहिए।", english: "This confidential knowledge may never be explained to those who are not austere, or devoted, or engaged in devotional service, nor to one who is envious of Me.", themes: ["Protected Knowledge", "Only for Devotees", "Not for Non-devotees", "Sacred"] },
  { chapterId: 18, id: 68, chapterName: "Liberation through Renunciation", skt: "य इमं परमं गुह्यं मद्भक्तेष्वभिधास्यति।\nभक्तिं मयि परां कृत्वा मामेवैष्यत्यसंशयः॥", iast: "ya imaṃ paramaṃ guhyaṃ madbhakteṣv abhidhāsyati\nbhaktiṃ mayi parāṃ kṛtvā mām evaiṣyaty asaṃśayaḥ", hindi: "जो इस परम गुह्य को मेरे भक्तों में बताएगा — मुझ में परा भक्ति करके निस्संदेह मुझे ही प्राप्त होगा।", english: "For one who explains this supreme secret to the devotees, pure devotional service is guaranteed, and at the end he will come back to Me.", themes: ["Teaching Others", "Supreme Devotion", "Liberation", "Service"] },
  { chapterId: 18, id: 69, chapterName: "Liberation through Renunciation", skt: "न च तस्मान्मनुष्येषु कश्चिन्मे प्रियकृत्तमः।\nभविता न च मे तस्मादन्यः प्रियतरो भुवि॥", iast: "na ca tasmān manuṣyeṣu kaścin me priyakṛttamaḥ\nbhavitā na ca me tasmād anyaḥ priyataro bhuvi", hindi: "उससे अधिक मुझे प्रिय करने वाला मनुष्यों में कोई नहीं है — और न होगा। उससे अधिक प्रिय पृथ्वी पर मेरे लिए दूसरा कोई नहीं।", english: "There is no servant in this world more dear to Me than he, nor will there ever be one more dear.", themes: ["Dearest to God", "Teaching Service", "Love", "Highest Devotee"] },
  { chapterId: 18, id: 70, chapterName: "Liberation through Renunciation", skt: "अध्येष्यते च य इमं धर्म्यं संवादमावयोः।\nज्ञानयज्ञेन तेनाहमिष्टः स्यामिति मे मतिः॥", iast: "adhyeṣyate ca ya imaṃ dharmyaṃ saṃvādam āvayoḥ\njñānayajñena tenāham iṣṭaḥ syām iti me matiḥ", hindi: "जो हम दोनों के इस धर्मयुक्त संवाद का अध्ययन करेगा — मेरे मत में उसके द्वारा ज्ञानयज्ञ से मेरी पूजा होगी।", english: "And I declare that he who studies this sacred conversation worships Me by his intelligence.", themes: ["Study of Gita", "Knowledge Sacrifice", "Worship", "Intelligence"] },
  { chapterId: 18, id: 71, chapterName: "Liberation through Renunciation", skt: "श्रद्धावाननसूयश्च शृणुयादपि यो नरः।\nसोऽपि मुक्तः शुभाँल्लोकान्प्राप्नुयात्पुण्यकर्मणाम्॥", iast: "śraddhāvān anasūyaś ca śṛṇuyād api yo naraḥ\nso'pi muktaḥ śubhāṃl lokān prāpnuyāt puṇyakarmaṇām", hindi: "जो श्रद्धावान् और ईर्ष्यारहित मनुष्य इसे सुनेगा — वह भी मुक्त होकर पुण्यकर्माओं के शुभ लोकों को प्राप्त होगा।", english: "And one who listens with faith and without envy becomes free from sinful reactions and attains to the auspicious planets where the pious dwell.", themes: ["Listening to Gita", "Faith", "Liberation", "Pious Worlds"] },
  { chapterId: 18, id: 72, chapterName: "Liberation through Renunciation", skt: "कच्चिदेतच्छ्रुतं पार्थ त्वयैकाग्रेण चेतसा।\nकच्चिदज्ञानसम्मोहः प्रनष्टस्ते धनञ्जय॥", iast: "kaccid etac chrutaṃ pārtha tvayaikāgreṇa cetasā\nkaccid ajñānasaṃmohaḥ pranaṣṭas te dhanañjaya", hindi: "हे पार्थ, हे धनञ्जय! क्या यह तुमने एकाग्र चित्त से सुना? और क्या तुम्हारा अज्ञानजन्य मोह नष्ट हो गया?", english: "O conqueror of wealth, O Partha, have you heard this with an attentive mind? And are your ignorance and illusions now dispelled?", themes: ["Krishna's Question", "Attention", "Illusion Dispelled", "Check"] },
  { chapterId: 18, id: 73, chapterName: "Liberation through Renunciation", skt: "अर्जुन उवाच।\nनष्टो मोहः स्मृतिर्लब्धा त्वत्प्रसादान्मयाच्युत।\nस्थितोऽस्मि गतसन्देहः करिष्ये वचनं तव॥", iast: "arjuna uvāca\nnaṣṭo mohaḥ smṛtir labdhā tvat prasādān mayācyuta\nsthito'smi gatasandehaḥ kariṣye vacanaṃ tava", hindi: "अर्जुन बोले — हे अच्युत! आपके प्रसाद से मेरा मोह नष्ट हो गया और स्मृति प्राप्त हो गई। मैं संशयरहित होकर स्थित हूँ। आपके वचन का पालन करूँगा।", english: "Arjuna said: My dear Krishna, O infallible one, my illusion is now gone. I have regained my memory by Your mercy, and I am now firm and free from doubt and am prepared to act according to Your instructions.", themes: ["Arjuna's Transformation", "Illusion Gone", "Certainty", "Ready to Act"] },
  { chapterId: 18, id: 74, chapterName: "Liberation through Renunciation", skt: "सञ्जय उवाच।\nइत्यहं वासुदेवस्य पार्थस्य च महात्मनः।\nसंवादमिममश्रौषमद्भुतं रोमहर्षणम्॥", iast: "sañjaya uvāca\nity ahaṃ vāsudevasya pārthasya ca mahātmanaḥ\nsaṃvādam imam aśrauṣam adbhutaṃ romaharṣaṇam", hindi: "संजय बोले — इस प्रकार मैंने वासुदेव और महात्मा पार्थ के इस अद्भुत और रोमांचकारी संवाद को सुना।", english: "Sanjaya said: Thus have I heard the conversation of two great souls, Krishna and Arjuna. And so wonderful is that message that my hair is standing on end.", themes: ["Sanjaya", "Wonder", "Dialogue", "Awe"] },
  { chapterId: 18, id: 75, chapterName: "Liberation through Renunciation", skt: "व्यासप्रसादाच्छ्रुतवानेतद्गुह्यमहं परम्।\nयोगं योगेश्वरात्कृष्णात्साक्षात्कथयतः स्वयम्॥", iast: "vyāsaprasādāc chrutavān etad guhyam ahaṃ param\nyogaṃ yogeśvarāt kṛṣṇāt sākṣāt kathayataḥ svayam", hindi: "व्यास के प्रसाद से मैंने इस परम गुह्य योग को स्वयं कथन करते हुए योगेश्वर कृष्ण से साक्षात् सुना।", english: "By the mercy of Vyasa, I have heard these most confidential talks directly from the master of all mysticism, Krishna, who was speaking personally to Arjuna.", themes: ["Vyasa's Grace", "Sanjaya's Gift", "Direct Hearing", "Yogeshvara Krishna"] },
  { chapterId: 18, id: 76, chapterName: "Liberation through Renunciation", skt: "राजन्संस्मृत्य संस्मृत्य संवादमिममद्भुतम्।\nकेशवार्जुनयोः पुण्यं हृष्यामि च मुहुर्मुहुः॥", iast: "rājan saṃsmṛtya saṃsmṛtya saṃvādam imam adbhutam\nkeśavārjunayoḥ puṇyaṃ hṛṣyāmi ca muhur muhuḥ", hindi: "हे राजन्! केशव और अर्जुन के इस पुण्य और अद्भुत संवाद को बार-बार स्मरण करके मैं बार-बार हर्षित होता हूँ।", english: "O King, as I repeatedly recall this wondrous and holy dialogue between Krishna and Arjuna, I take pleasure, being thrilled at every moment.", themes: ["Remembrance", "Joy", "Sanjaya", "Sacred Dialogue"] },
  { chapterId: 18, id: 77, chapterName: "Liberation through Renunciation", skt: "तच्च संस्मृत्य संस्मृत्य रूपमत्यद्भुतं हरेः।\nविस्मयो मे महान्राजन्हृष्यामि च पुनः पुनः॥", iast: "tac ca saṃsmṛtya saṃsmṛtya rūpam atyadbhutaṃ hareḥ\nvismayo me mahān rājan hṛṣyāmi ca punaḥ punaḥ", hindi: "हे राजन्! हरि के उस अत्यद्भुत रूप को भी बार-बार स्मरण करके मुझे महान् विस्मय होता है और मैं बार-बार हर्षित होता हूँ।", english: "O King, as I remember the wonderful form of Lord Krishna, I am struck with wonder more and more, and I rejoice again and again.", themes: ["Divine Form", "Wonder", "Sanjaya's Joy", "Hari"] },
  { chapterId: 18, id: 78, chapterName: "Liberation through Renunciation", skt: "यत्र योगेश्वरः कृष्णो यत्र पार्थो धनुर्धरः।\nतत्र श्रीर्विजयो भूतिर्ध्रुवा नीतिर्मतिर्मम॥", iast: "yatra yogeśvaraḥ kṛṣṇo yatra pārtho dhanurdharaḥ\ntatra śrīr vijayo bhūtir dhruvā nītir matir mama", hindi: "जहाँ योगेश्वर कृष्ण हैं और जहाँ धनुर्धर अर्जुन हैं — वहीं श्री, विजय, विभूति और अचल नीति है — ऐसा मेरा मत है।", english: "Wherever there is Krishna, the master of all mystics, and wherever there is Arjuna, the supreme archer, there will also certainly be opulence, victory, extraordinary power, and morality. That is my opinion.", themes: ["Final Verse", "Victory", "Opulence", "Krishna-Arjuna", "Conclusion"] },
];
